import{_ as i,C as a,o as h,c as s,ae as b,E as r,j as d,a as e}from"./chunks/framework.DNDrU9L4.js";const x=JSON.parse('{"title":"ハロハロミライ — 가사로 배우기","description":"","frontmatter":{},"headers":[],"relativePath":"japanese/lyrics/hello-hello-mirai.md","filePath":"japanese/lyrics/hello-hello-mirai.md"}'),u={name:"japanese/lyrics/hello-hello-mirai.md"};function p(c,t,q,m,k,f){const o=a("RomajiToggle"),n=a("Flashcard"),l=a("Quiz");return h(),s("div",null,[t[0]||(t[0]=b('<h1 id="ハロハロミライ-—-가사로-배우기" tabindex="-1">ハロハロミライ — 가사로 배우기 <a class="header-anchor" href="#ハロハロミライ-—-가사로-배우기" aria-label="Permalink to &quot;ハロハロミライ — 가사로 배우기&quot;">​</a></h1><h2 id="곡-소개" tabindex="-1">곡 소개 <a class="header-anchor" href="#곡-소개" aria-label="Permalink to &quot;곡 소개&quot;">​</a></h2><p>2024년 10월 2nd 싱글. 작사작곡: Yuki.KT. 8명의 우정과 미래를 향한 용기를 그린 곡입니다. 서로의 손을 잡고 함께 달리며, 두근거리는 가슴으로 꿈을 향해 나아가는 모습을 그렸습니다. 힘찬 멜로디와 응원의 메시지가 가슴에 울리는 큐티스트리트의 대표 곡입니다.</p><hr><h2 id="타이틀-분석" tabindex="-1">타이틀 분석 <a class="header-anchor" href="#타이틀-분석" aria-label="Permalink to &quot;타이틀 분석&quot;">​</a></h2><table tabindex="0"><thead><tr><th>단어</th><th>읽기</th><th>뜻</th></tr></thead><tbody><tr><td>ハロハロ</td><td>하로하로</td><td>Hello Hello (영어 반복)</td></tr><tr><td>ミライ</td><td>미라이</td><td>未来 / 미래</td></tr></tbody></table><p><strong>전체 해석</strong>: &quot;안녕 안녕, 미래야!&quot;</p><blockquote><p><strong>포인트</strong>: 외래어를 カタカナ(가타카나)로 표기하는 것은 일본어의 특징입니다. Hello → ハロー → 구어체로 ハロ가 됩니다. 未来(미래)를 미라이로 발음 그대로 가타카나로 쓴 것도 노래의 경쾌한 분위기를 살려줍니다.</p></blockquote><hr><h2 id="곡에서-배우는-단어" tabindex="-1">곡에서 배우는 단어 <a class="header-anchor" href="#곡에서-배우는-단어" aria-label="Permalink to &quot;곡에서 배우는 단어&quot;">​</a></h2><table tabindex="0"><thead><tr><th>일본어</th><th>읽기</th><th>뜻</th><th>예문</th></tr></thead><tbody><tr><td>未来</td><td>미라이</td><td>미래</td><td>未来を描こう！(미래를 그리자!)</td></tr><tr><td>描く</td><td>에가쿠</td><td>그리다, 묘사하다</td><td>夢を描く。(꿈을 그린다.)</td></tr><tr><td>全力</td><td>젠료쿠</td><td>전력, 최선</td><td>全力で走る！(전력으로 달린다!)</td></tr><tr><td>キラキラ</td><td>키라키라</td><td>반짝반짝</td><td>目がキラキラ輝く。(눈이 반짝반짝 빛난다.)</td></tr><tr><td>笑顔</td><td>에가오</td><td>미소, 웃는 얼굴</td><td>笑顔で前へ！(미소로 앞으로!)</td></tr><tr><td>胸</td><td>무네</td><td>가슴</td><td>胸がドキドキする。(가슴이 두근두근한다.)</td></tr><tr><td>ドキドキ</td><td>도키도키</td><td>두근두근</td><td>ドキドキが止まらない！(두근거림이 멈추지 않아!)</td></tr><tr><td>仲間</td><td>나카마</td><td>동료, 仲間</td><td>仲間と一緒に！(동료와 함께!)</td></tr><tr><td>夢</td><td>유메</td><td>꿈</td><td>夢を信じて。(꿈을 믿고.)</td></tr><tr><td>希望</td><td>키보</td><td>희망</td><td>希望の光。(희망의 빛.)</td></tr><tr><td>一緒</td><td>잇쇼</td><td>함께</td><td>一緒に行こう！(함께 가자!)</td></tr><tr><td>明日</td><td>아시타</td><td>내일</td><td>明日もキラキラ！(내일도 반짝반짝!)</td></tr><tr><td>勇気</td><td>유키</td><td>용기</td><td>勇気を出して！(용기를 내!)</td></tr><tr><td>信じる</td><td>신지루</td><td>믿다</td><td>自分を信じる。(자신을 믿는다.)</td></tr><tr><td>走る</td><td>하시루</td><td>달리다</td><td>一緒に走ろう！(함께 달리자!)</td></tr><tr><td>輝く</td><td>카가야쿠</td><td>빛나다</td><td>舞台で輝く。(무대에서 빛난다.)</td></tr><tr><td>手</td><td>테</td><td>손</td><td>手を繋いで。(손을 잡고.)</td></tr><tr><td>繋ぐ</td><td>츠나구</td><td>잇다, 연결하다</td><td>手を繋ごう。(손을 잇자.)</td></tr><tr><td>声</td><td>코에</td><td>목소리</td><td>声を合わせて！(목소리를 맞춰!)</td></tr></tbody></table><hr><h2 id="핵심-문법-3가지" tabindex="-1">핵심 문법 3가지 <a class="header-anchor" href="#핵심-문법-3가지" aria-label="Permalink to &quot;핵심 문법 3가지&quot;">​</a></h2><h3 id="_1-を描く-을-그리다" tabindex="-1">1. ～を描く (～을 그리다) <a class="header-anchor" href="#_1-を描く-을-그리다" aria-label="Permalink to &quot;1. ～を描く (～을 그리다)&quot;">​</a></h3><p>「描く」는 그림을 그리거나, 비유적으로 &quot;꿈/미래를 그린다&quot;는 표현에도 씁니다.</p><table tabindex="0"><thead><tr><th>일본어</th><th>뜻</th></tr></thead><tbody><tr><td>未来を描く</td><td>미래를 그리다</td></tr><tr><td>夢を描く</td><td>꿈을 그리다</td></tr><tr><td>笑顔を描く</td><td>미소를 그리다</td></tr><tr><td>絵を描く</td><td>그림을 그리다</td></tr></tbody></table><blockquote><p><strong>포인트</strong>: 「描く」는 에가쿠(그리다) 외에 「かく」로도 읽습니다. 같은 한자지만 문맥에 따라 읽기가 다르므로 주의하세요!</p></blockquote><hr><h3 id="_2-と一緒に-와-함께" tabindex="-1">2. ～と一緒に (～와 함께) <a class="header-anchor" href="#_2-と一緒に-와-함께" aria-label="Permalink to &quot;2. ～と一緒に (～와 함께)&quot;">​</a></h3><p>함께하는 동반자를 표현하는 패턴입니다. 우정과 팀워크를 주제로 하는 이 곡에서 자주 등장합니다.</p><table tabindex="0"><thead><tr><th>일본어</th><th>뜻</th></tr></thead><tbody><tr><td>仲間と一緒に</td><td>동료와 함께</td></tr><tr><td>みんなと一緒に</td><td>모두와 함께</td></tr><tr><td>君と一緒に</td><td>너와 함께</td></tr><tr><td>8人と一緒に</td><td>8명과 함께</td></tr></tbody></table><p><strong>응용</strong>: 「と一緒に」 뒤에 동사를 붙이면 완성됩니다.</p><table tabindex="0"><thead><tr><th>일본어</th><th>뜻</th></tr></thead><tbody><tr><td>仲間と一緒に走ろう</td><td>동료와 함께 달리자</td></tr><tr><td>君と一緒に夢を描きたい</td><td>너와 함께 꿈을 그리고 싶다</td></tr><tr><td>みんなと一緒に輝く</td><td>모두와 함께 빛난다</td></tr></tbody></table><hr><h3 id="_3-を信じて-을-믿고-—-て형-연결" tabindex="-1">3. ～を信じて (～을 믿고) — て형 연결 <a class="header-anchor" href="#_3-を信じて-을-믿고-—-て형-연결" aria-label="Permalink to &quot;3. ～を信じて (～을 믿고) — て형 연결&quot;">​</a></h3><p>동사의 て형은 &quot;~하고, ~하면서&quot;처럼 동작을 연결할 때 씁니다.</p><table tabindex="0"><thead><tr><th>기본형</th><th>て형</th><th>의미</th></tr></thead><tbody><tr><td>信じる</td><td>信じて</td><td>믿고, 믿으면서</td></tr><tr><td>走る</td><td>走って</td><td>달리고, 달리면서</td></tr><tr><td>繋ぐ</td><td>繋いで</td><td>잇고, 이으면서</td></tr><tr><td>輝く</td><td>輝いて</td><td>빛나고, 빛나면서</td></tr></tbody></table><p><strong>예문</strong>:</p><ul><li>夢を信じて、走り続けよう。(꿈을 믿고 계속 달리자.)</li><li>手を繋いで、前へ進もう。(손을 잡고 앞으로 나아가자.)</li></ul><blockquote><p><strong>포인트</strong>: て형으로 문장을 연결하면 더 자연스러운 일본어가 됩니다. 노래 가사에서도 이 패턴이 자주 등장합니다!</p></blockquote><hr><h2 id="문화-노트" tabindex="-1">문화 노트 <a class="header-anchor" href="#문화-노트" aria-label="Permalink to &quot;문화 노트&quot;">​</a></h2><h3 id="j-pop에서의-「仲間」-나카마-개념" tabindex="-1">J-POP에서의 「仲間」(나카마) 개념 <a class="header-anchor" href="#j-pop에서의-「仲間」-나카마-개념" aria-label="Permalink to &quot;J-POP에서의 「仲間」(나카마) 개념&quot;">​</a></h3><p>「仲間」는 단순한 &quot;친구&quot;를 넘어 &quot;함께 목표를 향해 나아가는 동료&quot;를 뜻합니다.</p><ul><li>일본의 만화, 애니메, 아이돌 문화에서 仲間는 핵심 가치</li><li>《ONE PIECE》의 나카마, 아이돌 그룹의 유닛 의식 모두 같은 뿌리</li><li>큐티스트리트 8명도 공연에서 「仲間」로서의 유대감을 강조</li></ul><h3 id="아이돌이-팬에게-전하는-응원-메시지" tabindex="-1">아이돌이 팬에게 전하는 응원 메시지 <a class="header-anchor" href="#아이돌이-팬에게-전하는-응원-메시지" aria-label="Permalink to &quot;아이돌이 팬에게 전하는 응원 메시지&quot;">​</a></h3><p>이 곡처럼 「勇気」(용기), 「全力」(전력), 「一緒に」(함께)를 담은 노래는 팬에게 직접 말을 거는 형식입니다.</p><ul><li><strong>コール&amp;レスポンス</strong>: 라이브에서 멤버가 &quot;ハロハロ！&quot;라고 외치면 팬이 &quot;ミライ！&quot;로 받는 형식</li><li><strong>ファンへのエール</strong>: 아이돌 노래가 팬의 일상에 용기를 주는 역할</li><li>팬과 아이돌이 함께 &quot;미래를 그린다&quot;는 메시지는 일본 아이돌 문화의 핵심</li></ul><hr><h2 id="핵심-표현-발음-가이드" tabindex="-1">핵심 표현 발음 가이드 <a class="header-anchor" href="#핵심-표현-발음-가이드" aria-label="Permalink to &quot;핵심 표현 발음 가이드&quot;">​</a></h2>',40)),r(o,{items:[{japanese:"ハロハロミライ",romaji:"haro haro mirai",meaning:"안녕 안녕, 미래야!"},{japanese:"未来を描こう",romaji:"mirai wo egakou",meaning:"미래를 그리자!"},{japanese:"仲間と一緒に走ろう",romaji:"nakama to issho ni hashirou",meaning:"동료와 함께 달리자!"},{japanese:"夢を信じて",romaji:"yume wo shinjite",meaning:"꿈을 믿고"},{japanese:"手を繋いで",romaji:"te wo tsunaide",meaning:"손을 잡고"},{japanese:"全力で走る",romaji:"zenryoku de hashiru",meaning:"전력으로 달린다!"}]}),t[1]||(t[1]=d("h2",{id:"단어-플래시카드",tabindex:"-1"},[e("단어 플래시카드 "),d("a",{class:"header-anchor",href:"#단어-플래시카드","aria-label":'Permalink to "단어 플래시카드"'},"​")],-1)),t[2]||(t[2]=d("p",null,"클릭해서 뒤집어 보세요!",-1)),r(n,{cardSetId:"lyrics-hello-hello-mirai",cards:[{front:"未来 (みらい)",back:"미래"},{front:"描く (えがく)",back:"그리다, 묘사하다"},{front:"全力 (ぜんりょく)",back:"전력, 최선"},{front:"仲間 (なかま)",back:"동료"},{front:"勇気 (ゆうき)",back:"용기"},{front:"信じる (しんじる)",back:"믿다"},{front:"希望 (きぼう)",back:"희망"},{front:"胸 (むね)",back:"가슴"},{front:"ドキドキ",back:"두근두근"},{front:"繋ぐ (つなぐ)",back:"잇다, 연결하다"},{front:"輝く (かがやく)",back:"빛나다"},{front:"声 (こえ)",back:"목소리"},{front:"走る (はしる)",back:"달리다"},{front:"一緒 (いっしょ)",back:"함께"},{front:"笑顔 (えがお)",back:"미소, 웃는 얼굴"}]}),t[3]||(t[3]=d("hr",null,null,-1)),t[4]||(t[4]=d("h2",{id:"가사-퀴즈",tabindex:"-1"},[e("가사 퀴즈 "),d("a",{class:"header-anchor",href:"#가사-퀴즈","aria-label":'Permalink to "가사 퀴즈"'},"​")],-1)),t[5]||(t[5]=d("p",null,"8문제에 도전! 어휘와 문법을 함께 확인해 봅시다.",-1)),r(l,{quizId:"lyrics-hello-hello-mirai",questions:[{q:"「未来」(みらい)의 뜻은?",options:["과거","현재","미래","영원"],answer:2},{q:"「仲間」(なかま)의 뜻은?",options:["선생님","동료","라이벌","팬"],answer:1},{q:"「勇気」(ゆうき)의 뜻은?",options:["희망","꿈","용기","노력"],answer:2},{q:"「信じる」의 뜻은?",options:["사랑하다","믿다","달리다","빛나다"],answer:1},{q:"「仲間と一緒に」의 뜻은?",options:["동료를 위해","동료와 함께","동료에게서","동료보다"],answer:1},{q:"「信じて」는 「信じる」의 어떤 형태?",options:["ます형","て형","ない형","た형"],answer:1},{q:"「ドキドキ」의 뜻은?",options:["반짝반짝","두근두근","울렁울렁","펄쩍펄쩍"],answer:1},{q:"「未来を描く」의 뜻은?",options:["미래를 달리다","미래를 기다리다","미래를 그리다","미래를 믿다"],answer:2}]})])}const P=i(u,[["render",p]]);export{x as __pageData,P as default};
